mapper.select:
select id, project_id, scene_id, seq_no, title, action_json, dialogue_json,
       source_refs_json, validation_status, warnings_json, created_at, updated_at
from scene_scripts
where project_id = #{projectId}
  and scene_id = #{sceneId}

mapper.update:
update scene_scripts
set seq_no = #{seqNo}
where project_id = #{projectId}
  and scene_id = #{sceneId}

mapper.delete:
delete from scene_scripts
where project_id = #{projectId}
  and scene_id = #{sceneId}
